// HasMatchRound applies the HasEdge predicate on the "match_round" edge.
func HasMatchRound() predicate.HighlightClip {
	return predicate.HighlightClip(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, MatchRoundTable, MatchRoundColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasMatchRoundWith applies the HasEdge predicate on the "match_round" edge with a given conditions (other predicates).
func HasMatchRoundWith(preds ...predicate.MatchRound) predicate.HighlightClip {
	return predicate.HighlightClip(func(s *sql.Selector) {
		step := newMatchRoundStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasSourceArtifact applies the HasEdge predicate on the "source_artifact" edge.
func HasSourceArtifact() predicate.HighlightClip {
	return predicate.HighlightClip(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SourceArtifactTable, SourceArtifactColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSourceArtifactWith applies the HasEdge predicate on the "source_artifact" edge with a given conditions (other predicates).
func HasSourceArtifactWith(preds ...predicate.MediaArtifact) predicate.HighlightClip {
	return predicate.HighlightClip(func(s *sql.Selector) {
		step := newSourceArtifactStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.HighlightClip) predicate.HighlightClip {
	return predicate.HighlightClip(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.HighlightClip) predicate.HighlightClip {
	return predicate.HighlightClip(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.HighlightClip) predicate.HighlightClip {
	return predicate.HighlightClip(sql.NotPredicates(p))
}
